// 重铸音效（base64 内嵌）
// 普通重铸音效
export const REFORGE_SOUND_DATA = 'data:audio/mp3;base64,';

// 砺金（金色）重铸音效
export const GOLD_REFORGE_SOUND_DATA = 'data:audio/mp3;base64,';

// 播放金色重铸音效
export function playGoldReforgeSound() {
  try {
    const audio = new Audio(GOLD_REFORGE_SOUND_DATA);
    audio.volume = 1.0;
    audio.play().catch(() => {});
  } catch (e) {
    // 静默处理
  }
}

